import React from 'react'

export default function (props){
  return (
    <div>
                {props.scores()}
                <button onClick={props.rematch}>play Again as {props.playerName}</button>
                <button onClick={props.changeUser}>play as different name</button>
                {props.theList()}
    </div>
  )
}
